import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import IssueCard from '../components/IssueCard';

const Dashboard = () => {
  const { user } = useAuth();
  const [issues, setIssues] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState({ type: '', status: '' });
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchIssues();
  }, [filter, searchTerm]);

  const fetchIssues = async () => {
    try {
      const params = new URLSearchParams();
      if (filter.type) params.append('type', filter.type);
      if (filter.status) params.append('status', filter.status);

      const response = await axios.get(`http://localhost:5000/api/issues?${params}`);
      let filteredIssues = response.data.issues;

      // Apply search filter
      if (searchTerm) {
        filteredIssues = filteredIssues.filter(issue =>
          issue.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
          issue.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
          issue.location?.address?.toLowerCase().includes(searchTerm.toLowerCase())
        );
      }

      setIssues(filteredIssues);
    } catch (error) {
      console.error('Error fetching issues:', error);
    } finally {
      setLoading(false);
    }
  };

  const updateIssueStatus = async (issueId, newStatus) => {
    try {
      await axios.put(`http://localhost:5000/api/issues/${issueId}/status`, {
        status: newStatus
      });

      // Update local state
      setIssues(issues.map(issue => 
        issue._id === issueId 
          ? { ...issue, status: newStatus, updatedAt: new Date() }
          : issue
      ));
    } catch (error) {
      console.error('Error updating issue status:', error);
      alert('Error updating issue status');
    }
  };

  const getStats = () => {
    const total = issues.length;
    const pending = issues.filter(i => i.status === 'pending').length;
    const inProgress = issues.filter(i => i.status === 'in_progress').length;
    const resolved = issues.filter(i => i.status === 'resolved').length;

    return { total, pending, inProgress, resolved };
  };

  const stats = getStats();

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64 bg-surface">
        <div className="text-center">
          <span className="material-symbols-outlined animate-spin text-4xl text-primary mb-4">refresh</span>
          <div className="text-lg text-on-surface-variant">Loading infrastructure issues...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-surface text-on-surface font-body selection:bg-primary-fixed selection:text-on-primary-fixed">
      {/* TopAppBar */}
      <header className="fixed top-0 w-full z-50 bg-surface/80 dark:bg-slate-900/80 backdrop-blur-xl shadow-sm dark:shadow-none">
        <div className="flex justify-between items-center px-6 py-4 w-full max-w-7xl mx-auto">
          <div className="flex items-center gap-3">
            <button className="p-2 -ml-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors active:scale-95 duration-200">
              <span className="material-symbols-outlined text-slate-500 dark:text-slate-400">menu</span>
            </button>
            <h1 className="text-xl font-bold tracking-tighter text-slate-900 dark:text-slate-50 font-['Inter']">CivicWatch</h1>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-blue-600 dark:text-blue-400 material-symbols-outlined p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors active:scale-95 duration-200">notifications</span>
          </div>
        </div>
      </header>

      <main className="pt-24 pb-32 px-4 max-w-7xl mx-auto space-y-8">
        {/* Hero Section / Analytics Overview */}
        <section className="space-y-6">
          <header className="flex justify-between items-end">
            <div>
              <span className="text-[11px] font-bold uppercase tracking-[0.2em] text-tertiary">System Health</span>
              <h2 className="text-3xl font-extrabold tracking-tight text-on-surface">Dashboard</h2>
            </div>
            <div className="flex items-center gap-2 bg-secondary-container px-3 py-1.5 rounded-full">
              <span className="w-2.5 h-2.5 bg-secondary rounded-full animate-pulse shadow-[0_0_8px_rgba(0,108,73,0.5)]"></span>
              <span className="text-xs font-bold text-on-secondary-container">Live</span>
            </div>
          </header>

          {/* Bento Grid Stats */}
          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-2 bg-surface-container-lowest p-6 rounded-xl shadow-sm flex flex-col justify-between overflow-hidden relative group">
              <div className="relative z-10">
                <span className="text-xs font-semibold text-on-surface-variant uppercase tracking-wider">Active Issues</span>
                <div className="flex items-baseline gap-2 mt-1">
                  <span className="text-4xl font-black text-primary">{stats.total}</span>
                  <span className="text-xs font-bold text-secondary flex items-center gap-0.5">
                    <span className="material-symbols-outlined text-xs">trending_down</span>
                    12%
                  </span>
                </div>
              </div>
              <div className="mt-4 h-16 w-full flex items-end gap-1">
                {/* Simplified Sparkline */}
                <div className="flex-1 bg-primary/10 rounded-t-sm h-1/2 group-hover:h-2/3 transition-all"></div>
                <div className="flex-1 bg-primary/10 rounded-t-sm h-3/4 group-hover:h-1/2 transition-all"></div>
                <div className="flex-1 bg-primary/10 rounded-t-sm h-2/3 group-hover:h-full transition-all"></div>
                <div className="flex-1 bg-primary/10 rounded-t-sm h-4/5 group-hover:h-3/4 transition-all"></div>
                <div className="flex-1 bg-primary/20 rounded-t-sm h-1/2 group-hover:h-2/3 transition-all"></div>
                <div className="flex-1 bg-primary/30 rounded-t-sm h-3/4 group-hover:h-1/2 transition-all"></div>
                <div className="flex-1 bg-primary/40 rounded-t-sm h-2/3 group-hover:h-full transition-all"></div>
                <div className="flex-1 bg-primary/60 rounded-t-sm h-full"></div>
              </div>
              <div className="absolute -right-4 -top-4 opacity-5 pointer-events-none">
                <span className="material-symbols-outlined text-[120px]">analytics</span>
              </div>
            </div>

            <div className="bg-surface-container-low p-4 rounded-xl">
              <span className="text-[10px] font-bold text-on-surface-variant uppercase tracking-widest">Resolved</span>
              <p className="text-2xl font-bold text-on-surface">{stats.resolved}</p>
              <div className="mt-2 w-full bg-outline-variant/20 h-1 rounded-full overflow-hidden">
                <div className="bg-secondary h-full w-[85%]"></div>
              </div>
            </div>

            <div className="bg-surface-container-low p-4 rounded-xl">
              <span className="text-[10px] font-bold text-on-surface-variant uppercase tracking-widest">Avg Response</span>
              <p className="text-2xl font-bold text-on-surface">4.2h</p>
              <div className="mt-2 w-full bg-outline-variant/20 h-1 rounded-full overflow-hidden">
                <div className="bg-tertiary h-full w-[60%]"></div>
              </div>
            </div>
          </div>
        </section>

        {/* Main Content Area: Issues Management */}
        <section className="space-y-6">
          <div className="flex flex-col gap-4">
            <div className="flex items-center justify-between">
              <h3 className="text-lg font-bold text-on-surface">Recent Reports</h3>
              <button className="text-primary text-sm font-semibold flex items-center gap-1">
                Filter <span className="material-symbols-outlined text-lg">filter_list</span>
              </button>
            </div>
            {/* Horizontal Filter Chips */}
            <div className="flex gap-2 overflow-x-auto hide-scrollbar pb-2">
              <button className="bg-primary text-on-primary px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap">All Issues</button>
              <button className="bg-surface-container-high text-on-surface-variant px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap">Critical</button>
              <button className="bg-surface-container-high text-on-surface-variant px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap">Potholes</button>
              <button className="bg-surface-container-high text-on-surface-variant px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap">Lighting</button>
              <button className="bg-surface-container-high text-on-surface-variant px-4 py-1.5 rounded-full text-xs font-bold whitespace-nowrap">Sanitation</button>
            </div>
          </div>

          {/* Issues List */}
          <div className="space-y-4">
            {issues.length > 0 ? (
              issues.slice(0, 3).map((issue) => (
                <div key={issue._id} className="bg-surface-container-lowest rounded-xl p-4 shadow-sm group hover:shadow-md transition-shadow">
                  <div className="flex gap-4">
                    <div className="w-16 h-16 rounded-lg flex-shrink-0 bg-slate-100 overflow-hidden relative">
                      {issue.image ? (
                        <img 
                          alt={issue.title} 
                          className="w-full h-full object-cover" 
                          src={issue.image}
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center bg-surface-container-low">
                          <span className="material-symbols-outlined text-2xl text-on-surface-variant">image_not_supported</span>
                        </div>
                      )}
                      <div className="absolute top-1 left-1">
                        <span className="bg-error text-on-error text-[8px] font-bold px-1.5 py-0.5 rounded-full uppercase">High</span>
                      </div>
                    </div>
                    <div className="flex-1 space-y-1">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-on-surface leading-tight">{issue.title}</h4>
                        <span className="text-[10px] text-on-surface-variant font-medium">
                          {new Date(issue.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} ago
                        </span>
                      </div>
                      <p className="text-xs text-on-surface-variant line-clamp-1">{issue.description}</p>
                      <div className="flex items-center gap-3 pt-1">
                        <div className="flex items-center gap-1 text-[10px] font-bold text-tertiary uppercase tracking-wider">
                          <span className="material-symbols-outlined text-xs">pending</span>
                          {issue.status === 'pending' ? 'Pending' : issue.status === 'in_progress' ? 'In Progress' : 'Resolved'}
                        </div>
                        <div className="flex items-center gap-1 text-[10px] text-on-surface-variant">
                          <span className="material-symbols-outlined text-xs">location_on</span>
                          {issue.location?.address || 'Unknown Location'}
                        </div>
                      </div>
                    </div>
                  </div>
                  <div className="mt-4 pt-4 border-t border-surface-container-high flex justify-end gap-2">
                    <button className="px-3 py-1.5 text-xs font-bold text-on-surface-variant bg-surface-container-high rounded-lg">View Details</button>
                    {user?.role === 'admin' && (
                      <button 
                        onClick={() => updateIssueStatus(issue._id, issue.status === 'resolved' ? 'pending' : 'resolved')}
                        className="px-3 py-1.5 text-xs font-bold text-on-primary bg-primary rounded-lg transition-transform active:scale-95"
                      >
                        Update Status
                      </button>
                    )}
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-12">
                <div className="bg-surface-container-lowest rounded-xl shadow-sm border border-outline-variant/20 p-12">
                  <div className="text-6xl mb-4">🔍</div>
                  <h3 className="text-xl font-semibold text-on-surface mb-2">No issues found</h3>
                  <p className="text-on-surface-variant mb-6">
                    {searchTerm || filter.type || filter.status 
                      ? 'Try adjusting your filters or search terms.' 
                      : 'Be the first to report an infrastructure issue in your area!'}
                  </p>
                  {!searchTerm && !filter.type && !filter.status && (
                    <button
                      onClick={() => window.location.href = '/report-issue'}
                      className="bg-primary hover:bg-primary/90 text-white px-6 py-3 rounded-lg font-medium transition-colors"
                    >
                      📝 Report an Issue
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        </section>
      </main>

      {/* BottomNavBar */}
      <nav className="fixed bottom-0 left-0 w-full flex justify-around items-center px-4 pb-6 pt-3 bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl border-t border-slate-100 dark:border-slate-800 shadow-[0_-4px_20px_rgba(0,0,0,0.05)] z-50 rounded-t-2xl md:hidden">
        <a className="flex flex-col items-center justify-center bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 rounded-xl px-4 py-1 active:scale-90 duration-200" href="/">
          <span className="material-symbols-outlined">home</span>
          <span className="text-[11px] font-medium font-['Inter'] uppercase tracking-widest mt-0.5">Home</span>
        </a>
        <a className="flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 px-4 py-1 hover:text-blue-500 transition-all active:scale-90 duration-200" href="/map">
          <span className="material-symbols-outlined">map</span>
          <span className="text-[11px] font-medium font-['Inter'] uppercase tracking-widest mt-0.5">Map</span>
        </a>
        <a className="flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 px-4 py-1 hover:text-blue-500 transition-all active:scale-90 duration-200" href="/report-issue">
          <span className="material-symbols-outlined">add_circle</span>
          <span className="text-[11px] font-medium font-['Inter'] uppercase tracking-widest mt-0.5">Report</span>
        </a>
        <a className="flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 px-4 py-1 hover:text-blue-500 transition-all active:scale-90 duration-200" href="#">
          <span className="material-symbols-outlined">person</span>
          <span className="text-[11px] font-medium font-['Inter'] uppercase tracking-widest mt-0.5">Account</span>
        </a>
      </nav>
    </div>
  );
};

export default Dashboard;
